CREATE TABLE singularity_raw.preparations (
    id                  BIGINT PRIMARY KEY,
    name                TEXT NOT NULL,
    created_at          TIMESTAMPTZ,
    updated_at          TIMESTAMPTZ,
    delete_after_export BOOLEAN,
    max_size            BIGINT,
    piece_size          BIGINT,
    no_inline           BOOLEAN,
    no_dag              BOOLEAN,
    min_piece_size      BIGINT
);


